import { createSetting } from '@shopex/finder'
export default (vm) => {
  return createSetting({
    columns: [
      { name: '券包標題	', key: 'title' },
      { name: '描述', key: 'package_describe', width: 130 },
      { name: '領取量', key: 'get_num' }
    ],
    actions: [
      {
        name: '查看',
        key: 'detail',
        type: 'button',
        buttonType: 'text',
        action: {
          type: 'link',
          handler: (val) => {
            vm.$router.push({
              path: `${vm.$route.path}/detail`,
              query: {
                type: 'detail',
                package_id: val[0].package_id
              }
            })
          }
        }
      },
      {
        name: '編輯',
        key: 'edit',
        type: 'button',
        buttonType: 'text',
        action: {
          type: 'link',
          handler: (val) => {
            vm.$router.push({
              path: `${vm.$route.path}/editor`,
              query: {
                type: 'edit',
                package_id: val[0].package_id
              }
            })
          }
        }
      },
      {
        name: '刪除',
        key: 'delete',
        type: 'button',
        buttonType: 'text',
        action: {
          type: 'link',
          handler: async (val) => {
            await vm.$confirm(`刪除券包？`, '提示', {
              confirmButtonText: '確定',
              cancelButtonText: '取消'
            })
            const { status } = await vm.$api.coupons_package.deleteCoupon({
              package_id: val[0].package_id
            })
            if (status) {
              vm.$message.success('刪除成功')
              vm.$refs.finder.refresh()
            } else {
              vm.$message.success('失敗')
            }
          }
        }
      }
    ]
  })
}
